'use client';

import Link from 'next/link';
import { ChevronRight } from 'lucide-react';
import { useState, useEffect } from 'react';

export default function HeroSection() {
  const [currentSlide, setCurrentSlide] = useState(0);

  const slides = [
    {
      title: 'Restoring Hope, Transforming Lives.',
      description: 'Join thousands of changemakers providing medical care, food, and education to those in need.',
      image: 'bg-gradient-to-br from-teal-50 to-blue-50',
    },
    {
      title: 'Every Act of Kindness Matters.',
      description: 'Your donation creates a ripple of positive change in communities across India.',
      image: 'bg-gradient-to-br from-blue-50 to-teal-50',
    },
    {
      title: 'Be the Change You Want to See.',
      description: 'Support our mission to create a more equitable and compassionate society.',
      image: 'bg-gradient-to-br from-orange-50 to-teal-50',
    },
  ];

  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentSlide((prev) => (prev + 1) % slides.length);
    }, 5000);
    return () => clearInterval(timer);
  }, []);

  const goToSlide = (index: number) => {
    setCurrentSlide(index);
  };

  const nextSlide = () => {
    setCurrentSlide((prev) => (prev + 1) % slides.length);
  };

  const prevSlide = () => {
    setCurrentSlide((prev) => (prev - 1 + slides.length) % slides.length);
  };

  return (
    <section className="relative overflow-hidden">
      <div className="relative h-96 md:h-[600px]">
        {/* Slides */}
        {slides.map((slide, index) => (
          <div
            key={index}
            className={`absolute inset-0 ${slide.image} transition-opacity duration-1000 ${
              index === currentSlide ? 'opacity-100' : 'opacity-0'
            }`}
          />
        ))}

        {/* Content */}
        <div className="relative h-full flex items-center justify-center">
          <div className="container-max text-center z-10">
            <div className="max-w-3xl mx-auto">
              <h1 className="text-4xl md:text-6xl font-bold text-gray-900 mb-6">
                {slides[currentSlide].title}
              </h1>
              <p className="text-lg md:text-xl text-gray-700 mb-8">
                {slides[currentSlide].description}
              </p>
              <div className="flex flex-col sm:flex-row gap-4 justify-center">
                <Link href="/donate" className="btn-primary inline-flex items-center justify-center gap-2">
                  Donate Monthly
                  <ChevronRight size={20} />
                </Link>
                <Link href="/about" className="btn-secondary inline-flex items-center justify-center gap-2">
                  How We Work
                  <ChevronRight size={20} />
                </Link>
              </div>
              <p className="text-sm text-gray-600 mt-8">
                Join 50,000+ donors worldwide
              </p>
            </div>
          </div>
        </div>

        {/* Navigation Arrows */}
        <button
          onClick={prevSlide}
          className="absolute left-4 top-1/2 -translate-y-1/2 z-20 bg-white/80 hover:bg-white p-2 rounded-full transition-colors"
          aria-label="Previous slide"
        >
          <ChevronRight size={24} className="rotate-180" />
        </button>
        <button
          onClick={nextSlide}
          className="absolute right-4 top-1/2 -translate-y-1/2 z-20 bg-white/80 hover:bg-white p-2 rounded-full transition-colors"
          aria-label="Next slide"
        >
          <ChevronRight size={24} />
        </button>

        {/* Dots */}
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-20 flex gap-2">
          {slides.map((_, index) => (
            <button
              key={index}
              onClick={() => goToSlide(index)}
              className={`w-3 h-3 rounded-full transition-all ${
                index === currentSlide ? 'bg-teal-600 w-8' : 'bg-white/60 hover:bg-white'
              }`}
              aria-label={`Go to slide ${index + 1}`}
            />
          ))}
        </div>
      </div>
    </section>
  );
}
